    13→namespace Orleans.Serialization.UnitTests
    14→{
    15→    /// <summary>
    16→    /// Tests for Orleans' JSON serialization support using System.Text.Json.
    17→    /// 
    18→    /// Orleans provides integration with System.Text.Json for scenarios where:
    19→    /// - JSON format is required for interoperability
    20→    /// - Human-readable serialization is needed for debugging
    21→    /// - Integration with external systems that expect JSON
    22→    /// 
    23→    /// The JSON codec in Orleans:
    24→    /// - Can be selectively applied to specific types using predicates
    25→    /// - Supports polymorphic serialization through Orleans' type system
    26→    /// - Provides both serialization and deep copy functionality
    27→    /// - Can be combined with Orleans' native serialization for optimal performance
    28→    /// </summary>
    29→    [Trait("Category", "BVT")]
    30→    public class JsonCodecTests : FieldCodecTester<MyJsonClass?, IFieldCodec<MyJsonClass?>>
    31→    {
    32→        public JsonCodecTests(ITestOutputHelper output) : base(output)
    33→        {
    34→        }
    35→
    36→        protected override void Configure(ISerializerBuilder builder)
    37→        {
    38→            builder.AddJsonSerializer(isSupported: type => type.GetCustomAttribute<MyJsonSerializableAttribute>(inherit: false) is not null);
