using System;
using System.Text.Json.Nodes;
using Microsoft.Extensions.DependencyInjection;
using Orleans.Serialization;
using Xunit;

namespace Orleans.Serialization.UnitTests
{
    public class JsonValueBugReproTests
    {
        private readonly ServiceProvider _serviceProvider;

        public JsonValueBugReproTests()
        {
            var services = new ServiceCollection();
            services.AddSerializer(builder =>
            {
                builder.AddJsonSerializer();
            });
            _serviceProvider = services.BuildServiceProvider();
        }

        [Fact]
        public void JsonValue_ShouldSerializeAndDeserializeWithoutCastException()
        {
            // Arrange
            var original = JsonValue.Create(42);
            var codecProvider = _serviceProvider.GetRequiredService<ICodecProvider>();
            var codec = codecProvider.GetCodec(original.GetType());

            // Act & Assert - This should not throw InvalidCastException
            var result = TestHelpers.RoundTripThroughCodec(original, codec, _serviceProvider);

            Assert.IsType<JsonValue>(result);
            Assert.Equal(original.GetValue<int>(), ((JsonValue)result).GetValue<int>());
        }

        [Fact]
        public void JsonNode_ShouldHandleJsonValueWithoutCastException()
        {
            // Arrange
            JsonNode original = JsonValue.Create(123);
            var codecProvider = _serviceProvider.GetRequiredService<ICodecProvider>();
            var codec = codecProvider.GetCodec(original.GetType());

            // Act & Assert - This should not throw InvalidCastException
            var result = TestHelpers.RoundTripThroughCodec(original, codec, _serviceProvider);

            Assert.IsType<JsonValue>(result);
            Assert.Equal(original.GetValue<int>(), ((JsonValue)result).GetValue<int>());
        }

        [Fact]
        public void JsonArray_WithJsonValues_ShouldRoundTripCorrectly()
        {
            // Arrange
            var original = new JsonArray(JsonValue.Create(1), JsonValue.Create("hello"), JsonValue.Create(true));
            var codecProvider = _serviceProvider.GetRequiredService<ICodecProvider>();
            var codec = codecProvider.GetCodec(original.GetType());

            // Act & Assert
            var result = TestHelpers.RoundTripThroughCodec(original, codec, _serviceProvider);

            Assert.Equal(original.Count, ((JsonArray)result).Count);
            Assert.Equal(original[0].GetValue<int>(), ((JsonArray)result)[0].GetValue<int>());
            Assert.Equal(original[1].GetValue<string>(), ((JsonArray)result)[1].GetValue<string>());
            Assert.Equal(original[2].GetValue<bool>(), ((JsonArray)result)[2].GetValue<bool>());
        }
    }

    public static class TestHelpers
    {
        public static object RoundTripThroughCodec(object original, IFieldCodec codec, IServiceProvider serviceProvider)
        {
            var serializer = serviceProvider.GetRequiredService<Serializer>();

            // Serialize
            var serialized = serializer.SerializeToArray(original);

            // Deserialize
            var deserialized = serializer.Deserialize(serialized);

            return deserialized;
        }
    }
}

